import Peer, { DataConnection } from 'peerjs';
import { GameMessage } from '../types';

export class PeerManager {
  private peer: Peer | null = null;
  private conn: DataConnection | null = null;
  private myId: string = '';

  // Callbacks
  public onData: ((data: GameMessage) => void) | null = null;
  public onConnect: (() => void) | null = null;
  public onClose: (() => void) | null = null;

  constructor() {}

  public init(username: string): Promise<string> {
    return new Promise((resolve, reject) => {
      // Generate a short ID for usability (6 chars)
      // Note: In production, check for collisions. PeerJS cloud usually takes any string.
      const shortId = Math.random().toString(36).substring(2, 8).toUpperCase();

      this.peer = new Peer(shortId, {
        debug: 1,
      });

      this.peer.on('open', (id) => {
        this.myId = id;
        console.log('My Peer ID is: ' + id);
        resolve(id);
      });

      this.peer.on('connection', (conn) => {
        this.handleConnection(conn);
      });

      this.peer.on('error', (err) => {
        console.error(err);
        reject(err);
      });
    });
  }

  public connectTo(peerId: string): void {
    if (!this.peer) return;
    const conn = this.peer.connect(peerId.toUpperCase());
    this.handleConnection(conn);
  }

  private handleConnection(conn: DataConnection) {
    this.conn = conn;

    this.conn.on('open', () => {
      console.log('Connection established');
      if (this.onConnect) this.onConnect();
    });

    this.conn.on('data', (data) => {
      if (this.onData) this.onData(data as GameMessage);
    });

    this.conn.on('close', () => {
      console.log('Connection closed');
      this.conn = null;
      if (this.onClose) this.onClose();
    });

    this.conn.on('error', (err) => {
      console.error('Connection error:', err);
    });
  }

  public send(msg: GameMessage) {
    if (this.conn && this.conn.open) {
      this.conn.send(msg);
    } else {
      console.warn('Connection not open, cannot send message');
    }
  }

  public getMyId() {
    return this.myId;
  }

  public destroy() {
    if (this.peer) {
      this.peer.destroy();
      this.peer = null;
    }
    this.conn = null;
  }
}

export const peerManager = new PeerManager();

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Chess, Move, Square } from 'chess.js';
import { motion, AnimatePresence } from 'framer-motion';
import { peerManager } from '../services/PeerManager';
import { GameMessage } from '../types';
import { ChevronLeft, RotateCcw } from 'lucide-react';

interface ChessGameProps {
  isHost: boolean;
  onExit: () => void;
  onGameOver: (winner: string) => void;
}

const ChessGame: React.FC<ChessGameProps> = ({ isHost, onExit, onGameOver }) => {
  const [game, setGame] = useState(new Chess());
  const [board, setBoard] = useState(game.board());
  const [selectedSquare, setSelectedSquare] = useState<Square | null>(null);
  const [possibleMoves, setPossibleMoves] = useState<string[]>([]);
  const [playerColor] = useState<'w' | 'b'>(isHost ? 'w' : 'b');
  const [capturedWhite, setCapturedWhite] = useState<string[]>([]);
  const [capturedBlack, setCapturedBlack] = useState<string[]>([]);
  const moveSoundRef = useRef<HTMLAudioElement | null>(null);

  // Sync with peer
  useEffect(() => {
    peerManager.onData = (msg: GameMessage) => {
      if (msg.type === 'MOVE') {
        const { from, to, promotion } = msg.payload;
        makeMove(from, to, promotion, false); // false = don't send back
      } else if (msg.type === 'RESTART') {
        const newGame = new Chess();
        setGame(newGame);
        setBoard(newGame.board());
        setCapturedWhite([]);
        setCapturedBlack([]);
      }
    };
    return () => {
        // Cleanup handled in parent usually, but resetting callback good practice
        peerManager.onData = null; 
    }
  }, [game]); // Depend on game to ensure closure has latest state if needed, though chess.js instance mutates

  // Helper to play sound
  const playMoveSound = () => {
     // Simple beep or load a file. For PWA, we might want to lazy load.
     // Implementing a simple oscillator for efficiency
     try {
       const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
       if (AudioContext) {
         const ctx = new AudioContext();
         const osc = ctx.createOscillator();
         const gain = ctx.createGain();
         osc.connect(gain);
         gain.connect(ctx.destination);
         osc.frequency.setValueAtTime(200, ctx.currentTime);
         gain.gain.setValueAtTime(0.1, ctx.currentTime);
         gain.gain.exponentialRampToValueAtTime(0.00001, ctx.currentTime + 0.1);
         osc.start();
         osc.stop(ctx.currentTime + 0.1);
       }
     } catch (e) {
       // Ignore audio errors
     }
  };

  const makeMove = (from: string, to: string, promotion: string = 'q', emit: boolean = true) => {
    try {
      const moveAttempt = { from, to, promotion };
      const result = game.move(moveAttempt);

      if (result) {
        setBoard(game.board());
        playMoveSound();
        setSelectedSquare(null);
        setPossibleMoves([]);

        // Update captures
        if (result.captured) {
            if (result.color === 'w') {
                setCapturedBlack(prev => [...prev, result.captured!]);
            } else {
                setCapturedWhite(prev => [...prev, result.captured!]);
            }
        }

        if (emit) {
          peerManager.send({
            type: 'MOVE',
            payload: { from, to, promotion }
          });
        }

        if (game.isGameOver()) {
            let winner = 'Draw';
            if (game.isCheckmate()) {
                winner = game.turn() === 'w' ? 'Black' : 'White';
            }
            setTimeout(() => onGameOver(winner), 500);
        }
      }
    } catch (e) {
      console.error("Invalid move", e);
    }
  };

  const handleSquareClick = (square: Square, piece: { type: string; color: string } | null) => {
    // If not my turn, ignore
    if (game.turn() !== playerColor) return;

    // If selecting own piece
    if (piece && piece.color === playerColor) {
      if (selectedSquare === square) {
        setSelectedSquare(null);
        setPossibleMoves([]);
      } else {
        setSelectedSquare(square);
        const moves = game.moves({ square, verbose: true }).map((m: any) => m.to);
        setPossibleMoves(moves);
      }
      return;
    }

    // If clicking a destination square
    if (selectedSquare) {
      if (possibleMoves.includes(square)) {
        makeMove(selectedSquare, square);
      } else {
        setSelectedSquare(null);
        setPossibleMoves([]);
      }
    }
  };

  // Rendering helpers
  const getPieceIcon = (type: string, color: string) => {
    const symbols: Record<string, string> = {
      p: '♟', n: '♞', b: '♝', r: '♜', q: '♛', k: '♚'
    };
    return symbols[type] || '';
  };

  const isDarkSquare = (i: number, j: number) => (i + j) % 2 === 1;

  // Board Rotation: If player is Black, rotate board
  const boardDisplay = playerColor === 'w' ? board : [...board].reverse().map(row => [...row].reverse());

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 pb-20 md:pb-4">

      {/* HUD - Top (Opponent) */}
      <div className="w-full max-w-md flex justify-between items-center mb-4 glass-panel p-3 rounded-lg shadow-sm">
        <div className="flex items-center gap-2">
            <div className={`w-3 h-3 rounded-full ${game.turn() !== playerColor ? 'bg-green-500 animate-pulse' : 'bg-gray-300'}`}></div>
            <span className="font-serif font-bold text-gray-700">Opponent</span>
        </div>
        <div className="flex gap-1 text-xl">
             {/* Captured pieces by opponent (my pieces) */}
             {playerColor === 'w' ? capturedWhite.map((p, i) => <span key={i} className="text-black">{getPieceIcon(p, 'w')}</span>) 
                                  : capturedBlack.map((p, i) => <span key={i} className="text-white drop-shadow-md">{getPieceIcon(p, 'b')}</span>)}
        </div>
      </div>

      {/* Board */}
      <div className="relative p-1 bg-[#4a3b2b] rounded shadow-2xl">
        <div className="grid grid-cols-8 border-4 border-[#3d2f20]">
          {boardDisplay.map((row, i) => (
            row.map((square, j) => {
              // Calculate actual coordinates based on rotation
              const actualRowIndex = playerColor === 'w' ? i : 7 - i;
              const actualColIndex = playerColor === 'w' ? j : 7 - j;
              const squareName = String.fromCharCode(97 + actualColIndex) + (8 - actualRowIndex) as Square;

              const isSelected = selectedSquare === squareName;
              const isPossible = possibleMoves.includes(squareName);
              const isDark = isDarkSquare(actualRowIndex, actualColIndex);

              return (
                <div
                  key={`${i}-${j}`}
                  onClick={() => handleSquareClick(squareName, square)}
                  className={`
                    w-10 h-10 sm:w-14 sm:h-14 md:w-16 md:h-16 flex items-center justify-center text-3xl sm:text-4xl cursor-pointer relative
                    ${isDark ? 'bg-[#b58863]' : 'bg-[#f0d9b5]'}
                    ${isSelected ? 'ring-inset ring-4 ring-yellow-400' : ''}
                  `}
                >
                  {/* Position Hint Dot */}
                  {isPossible && !square && (
                    <div className="absolute w-3 h-3 bg-black/20 rounded-full" />
                  )}
                  {isPossible && square && (
                     <div className="absolute inset-0 ring-inset ring-4 ring-black/20" />
                  )}

                  {square && (
                    <motion.div
                      layoutId={`piece-${squareName}`} // Simple layout animation, could be improved with unique IDs per piece instance
                      className={`${square.color === 'w' ? 'text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)]' : 'text-black drop-shadow-[0_1px_1px_rgba(255,255,255,0.5)]'}`}
                    >
                      {getPieceIcon(square.type, square.color)}
                    </motion.div>
                  )}

                  {/* Coordinates for elegance */}
                  {j === 0 && <span className={`absolute left-0.5 top-0 text-[8px] sm:text-[10px] ${isDark ? 'text-[#f0d9b5]' : 'text-[#b58863]'}`}>{playerColor === 'w' ? 8-i : i+1}</span>}
                  {i === 7 && <span className={`absolute right-0.5 bottom-0 text-[8px] sm:text-[10px] ${isDark ? 'text-[#f0d9b5]' : 'text-[#b58863]'}`}>{String.fromCharCode(97 + (playerColor === 'w' ? j : 7-j))}</span>}
                </div>
              );
            })
          ))}
        </div>
      </div>

      {/* HUD - Bottom (Player) */}
      <div className="w-full max-w-md flex justify-between items-center mt-4 glass-panel p-3 rounded-lg shadow-sm">
        <div className="flex items-center gap-2">
            <div className={`w-3 h-3 rounded-full ${game.turn() === playerColor ? 'bg-green-500 animate-pulse' : 'bg-gray-300'}`}></div>
            <span className="font-serif font-bold text-king-gold">You</span>
        </div>
        <div className="flex gap-1 text-xl">
             {/* Captured pieces by me (opponent pieces) */}
             {playerColor === 'w' ? capturedBlack.map((p, i) => <span key={i} className="text-black">{getPieceIcon(p, 'b')}</span>) 
                                  : capturedWhite.map((p, i) => <span key={i} className="text-white drop-shadow-md">{getPieceIcon(p, 'w')}</span>)}
        </div>
      </div>

      <button onClick={onExit} className="mt-8 flex items-center gap-2 text-gray-500 hover:text-red-500 transition-colors">
        <ChevronLeft size={20} /> Leave Game
      </button>

    </div>
  );
};

export default ChessGame;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { peerManager } from '../services/PeerManager';
import { GameMessage, LudoState } from '../types';
import { ChevronLeft, Dices } from 'lucide-react';

interface LudoGameProps {
  isHost: boolean;
  onExit: () => void;
  onGameOver: (winner: string) => void;
}

