// Types for local app state
type ViewState = 'WELCOME' | 'SELECTION' | 'LOBBY' | 'GAME';
type LobbyMode = 'CREATE' | 'JOIN' | null;

const App = () => {
  const [view, setView] = useState<ViewState>('WELCOME');
