      // Setup listener for incoming connection
      peerManager.onConnect = () => {
        console.log("Opponent Connected!");
        setIsConnected(true);
        // Host initiates handshake with game type
        setTimeout(() => {
          peerManager.send({
            type: 'HANDSHAKE',
