      await peerManager.init(username);
      peerManager.connectTo(joinCode);

      // Guest waits for handshake to know game type and confirm connection
      peerManager.onData = (msg: GameMessage) => {
        if (msg.type === 'HANDSHAKE') {
          console.log("Handshake received:", msg.payload);
          setGameType(msg.payload.gameType);
          setIsConnected(true);
          setView('GAME');
