              <div className="space-y-3">
                 <button 
                   onClick={() => setWinner(null)} // In a real app, this would trigger a restart negotiation
                   className="w-full py-3 bg-king-gold text-white rounded-xl font-bold hover:brightness-110"
                 >
                   Play Again
                 </button>
                 <button 
                   onClick={resetGame}
                   className="w-full py-3 bg-gray-100 text-gray-600 rounded-xl font-bold hover:bg-gray-200"
                 >
                   Return to Lobby
                 </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

// Simple helper icon
const ChevronLeftIcon = () => (
