  playMode: PlayMode;
  onExit: () => void;
  onGameOver: (winner: string) => void;
}

const LudoGame: React.FC<LudoGameProps> = ({ isHost, playMode, onExit, onGameOver }) => {
  const isOnline = playMode === 'ONLINE';
  const myColor = isHost ? 'red' : 'yellow'; // Only matters for Online

  const [gameState, setGameState] = useState<LudoState>({
    redTokens: [-1, -1, -1, -1], // -1 means in base
    yellowTokens: [-1, -1, -1, -1],
    currentTurn: 'red',
    diceValue: null,
    canRoll: true,
    winner: null
  });

  const [isRolling, setIsRolling] = useState(false);

  useEffect(() => {
    if (!isOnline) return;

    peerManager.onData = (msg: GameMessage) => {
      if (msg.type === 'SYNC_STATE') {
        setGameState(msg.payload as LudoState);
      }
    };
  }, [isOnline]);

  const rollDice = async () => {
    if (!gameState.canRoll || isRolling) return;
    setIsRolling(true);
    // Simulate dice roll (replace with actual logic)
    const diceValue = Math.floor(Math.random() * 6) + 1;
    setTimeout(() => {
      setIsRolling(false);
      setGameState(prev => ({ ...prev, diceValue: diceValue, canRoll: false }));
    }, 1000);
  };

