        tokens[tokenIndex] = newPosition;
      }

      return {
        ...prev,
        [`${myColor}Tokens` as 'redTokens' | 'yellowTokens' ]: tokens,
        canRoll: true,
        currentTurn: prev.currentTurn === 'red' ? 'yellow' : 'red', // basic turn change
        diceValue: null,
      };
    });
  };

  // UI rendering (Simplified for brevity)
  return (
    <div>
      {/* Game UI here, including tokens, dice, etc. */}
      {isOnline && (
        <motion.button
          onClick={onExit}
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          style={{ position: 'absolute', top: '10px', left: '10px' }}
