import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { peerManager } from '../services/PeerManager';
import { GameMessage, LudoState, PlayMode } from '../types';
import { ChevronLeft, Dices } from 'lucide-react';

interface LudoGameProps {
  isHost: boolean;
  playMode: PlayMode;
  onExit: () => void;
  onGameOver: (winner: string) => void;
}

const LudoGame: React.FC<LudoGameProps> = ({ isHost, playMode, onExit, onGameOver }) => {
  const isOnline = playMode === 'ONLINE';
  const myColor = isHost ? 'red' : 'yellow'; // Only matters for Online

  const [gameState, setGameState] = useState<LudoState>({
    redTokens: [-1, -1, -1, -1], // -1 means in base
    yellowTokens: [-1, -1, -1, -1],
    currentTurn: 'red',
    diceValue: null,
    canRoll: true,
    winner: null
  });

  const [isRolling, setIsRolling] = useState(false);

  useEffect(() => {
    if (!isOnline) return;

    peerManager.onData = (msg: GameMessage) => {
      if (msg.type === 'SYNC_STATE') {
        setGameState(msg.payload);
      } else if (msg.type === 'ROLL_DICE') {
         setIsRolling(true);
         setTimeout(() => setIsRolling(false), 500);
      }
    };
  }, [isHost, isOnline]);

  const broadcastState = (newState: LudoState) => {
    setGameState(newState);
    if (isOnline) {
        peerManager.send({ type: 'SYNC_STATE', payload: newState });
    }
    if (newState.winner) {
        onGameOver(newState.winner);
    }
  };

  const rollDice = () => {
    // Online Restriction
    if (isOnline && (gameState.currentTurn !== myColor || !gameState.canRoll)) return;
    // Offline Check
    if (!isOnline && !gameState.canRoll) return;

    setIsRolling(true);
    if (isOnline) peerManager.send({ type: 'ROLL_DICE', payload: {} });

    setTimeout(() => {
      setIsRolling(false);
      const roll = Math.floor(Math.random() * 6) + 1;

      const newState = { ...gameState, diceValue: roll, canRoll: false };

      // Check if any moves are possible
      const activeTokens = newState.currentTurn === 'red' ? newState.redTokens : newState.yellowTokens;
      const hasMoves = activeTokens.some(pos => canMove(pos, roll));

      if (!hasMoves) {
        // Skip turn
        setTimeout(() => {
            const nextTurn = newState.currentTurn === 'red' ? 'yellow' : 'red';
            broadcastState({ ...newState, currentTurn: nextTurn, canRoll: true, diceValue: null });
        }, 1000);
      } else {
        broadcastState(newState);
      }
    }, 500);
  };

  const canMove = (pos: number, roll: number) => {
      if (pos === -1) return roll === 6; // Need 6 to start
      if (pos >= 52) return pos + roll <= 57; // Exact enter
      return true; 
  };

  const moveToken = (tokenIndex: number) => {
    // Online Restriction
    if (isOnline && (gameState.currentTurn !== myColor)) return;
    // General Validation
    if (gameState.canRoll || !gameState.diceValue) return;

    const isRedTurn = gameState.currentTurn === 'red';
    const tokens = isRedTurn ? [...gameState.redTokens] : [...gameState.yellowTokens];
    const currentPos = tokens[tokenIndex];

    if (!canMove(currentPos, gameState.diceValue)) return;

    // Execute Move
    let newPos = currentPos;
    if (currentPos === -1) {
        newPos = 0; 
    } else {
        newPos += gameState.diceValue;
    }

    tokens[tokenIndex] = newPos;

    // Check Win
    const allHome = tokens.every(t => t === 57);
    const winner = allHome ? gameState.currentTurn : null;

    // Next turn logic (Roll 6 = extra turn)
    const nextTurn: 'red' | 'yellow' = (gameState.diceValue === 6 && !winner) 
        ? gameState.currentTurn 
        : (gameState.currentTurn === 'red' ? 'yellow' : 'red');

    const newState: LudoState = {
        ...gameState,
        [isRedTurn ? 'redTokens' : 'yellowTokens']: tokens,
        currentTurn: nextTurn,
        canRoll: true, 
        diceValue: null,
        winner
    };

    broadcastState(newState);
  };

  const renderToken = (color: 'red' | 'yellow', index: number, pos: number) => {
      // Logic for interactivity
      const isMyTurn = gameState.currentTurn === color;

      // Allow pickup if: 
      // 1. It is the turn of this token's color
      // 2. Dice has been rolled (!canRoll && diceValue)
      // 3. Online: Must be my assigned color. Offline: Always allowed if turn matches.
      const isMyColor = isOnline ? color === myColor : true;
      const canPick = isMyColor && isMyTurn && !gameState.canRoll && gameState.diceValue && canMove(pos, gameState.diceValue);

      return (
          <motion.div
            key={`${color}-${index}`}
            whileHover={canPick ? { scale: 1.2 } : {}}
            whileTap={canPick ? { scale: 0.9 } : {}}
            onClick={() => canPick && moveToken(index)}
            className={`
                w-8 h-8 rounded-full shadow-lg border-2 border-white flex items-center justify-center
                ${color === 'red' ? 'bg-red-500' : 'bg-yellow-400'}
                ${canPick ? 'cursor-pointer animate-bounce' : 'cursor-default opacity-90'}
            `}
          >
              <span className="text-xs font-bold text-black/50">{index + 1}</span>
          </motion.div>
      );
  };

  // Label Logic
  const topLabel = isOnline ? (myColor === 'red' ? "Yellow (Opponent)" : "Red (Opponent)") : "Yellow";
  const bottomLabel = isOnline ? (myColor === 'red' ? "Red (You)" : "Yellow (You)") : "Red";

  return (
    <div className="flex flex-col items-center min-h-screen p-4">
        <h2 className="text-3xl font-serif text-king-gold mb-6">Ludo Royal</h2>

        {/* Status */}
        <div className="glass-panel px-6 py-2 rounded-full mb-8 flex items-center gap-4">
             <div className={`text-lg font-bold ${gameState.currentTurn === 'red' ? 'text-red-500' : 'text-gray-400'}`}>Red</div>
             <div className="text-gray-300">VS</div>
             <div className={`text-lg font-bold ${gameState.currentTurn === 'yellow' ? 'text-yellow-400' : 'text-gray-400'}`}>Yellow</div>
        </div>

        {/* Dice Area */}
        <div className="relative mb-12">
            <button
                onClick={rollDice}
                // Disabled if not your turn (Online) or not time to roll (Offline)
                disabled={isOnline ? (gameState.currentTurn !== myColor || !gameState.canRoll) : (!gameState.canRoll)}
                className={`
                    w-24 h-24 rounded-2xl bg-gradient-to-br from-king-gold to-yellow-600 shadow-xl
                    flex items-center justify-center text-4xl text-white font-serif
                    transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed
                    ${gameState.canRoll && (!isOnline || gameState.currentTurn === myColor) ? 'ring-4 ring-white/50 animate-pulse' : ''}
                `}
            >
                <motion.div
                    animate={isRolling ? { rotate: 360 } : {}}
                    transition={{ duration: 0.5, repeat: isRolling ? Infinity : 0 }}
                >
                    {isRolling ? <Dices size={48} /> : (gameState.diceValue || <Dices size={48} />)}
                </motion.div>
            </button>
            <div className="text-center mt-4 font-bold text-gray-500">
                {(!isOnline || gameState.currentTurn === myColor) 
                    ? (gameState.canRoll ? "Roll Dice" : "Move Token") 
                    : "Opponent's Turn"}
            </div>
        </div>

        {/* Board / Tokens Area */}
        <div className="w-full max-w-md bg-white/50 backdrop-blur-sm p-6 rounded-3xl shadow-inner border border-white/20">
            <div className="mb-6">
                <h3 className="text-red-600 font-bold mb-2 flex justify-between">
                    <span>{isOnline && myColor === 'red' ? 'Red (You)' : 'Red Team'}</span>
                    {gameState.currentTurn === 'red' && <span className="text-xs bg-red-100 text-red-600 px-2 py-1 rounded">Active</span>}
                </h3>
                <div className="flex justify-between bg-white/40 p-4 rounded-xl">
                    {gameState.redTokens.map((pos, i) => (
                        <div key={i} className="flex flex-col items-center gap-1">
                            {renderToken('red', i, pos)}
                            <span className="text-[10px] text-gray-500">{pos === -1 ? 'Base' : (pos === 57 ? 'Home' : `Pos: ${pos}`)}</span>
                        </div>
                    ))}
                </div>
            </div>

            <div className="border-t border-gray-300/30 my-4"></div>

            <div>
                <h3 className="text-yellow-600 font-bold mb-2 flex justify-between">
                    <span>{isOnline && myColor === 'yellow' ? 'Yellow (You)' : 'Yellow Team'}</span>
                    {gameState.currentTurn === 'yellow' && <span className="text-xs bg-yellow-100 text-yellow-600 px-2 py-1 rounded">Active</span>}
                </h3>
                <div className="flex justify-between bg-white/40 p-4 rounded-xl">
                    {gameState.yellowTokens.map((pos, i) => (
                         <div key={i} className="flex flex-col items-center gap-1">
                            {renderToken('yellow', i, pos)}
                            <span className="text-[10px] text-gray-500">{pos === -1 ? 'Base' : (pos === 57 ? 'Home' : `Pos: ${pos}`)}</span>
                        </div>
                    ))}
                </div>
            </div>
        </div>

        <button onClick={onExit} className="mt-auto mb-4 flex items-center gap-2 text-gray-400 hover:text-red-500 transition-colors">
            <ChevronLeft size={20} /> Leave Game
        </button>
    </div>
  );
};

