          className="bg-white p-6 rounded-2xl shadow-md border border-gray-100 flex items-center gap-4 text-left hover:border-king-gold transition-all"
        >
          <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-600">
            <WifiOff size={24} />
          </div>
          <div className="flex-1">
            <h3 className="font-bold text-lg text-king-dark">Pass & Play</h3>
            <p className="text-sm text-gray-500">Offline on this device</p>
          </div>
          <ArrowRight size={20} className="text-gray-300" />
        </motion.button>
      </div>
    </motion.div>
  );

  const renderPlayerSelect = () => (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="flex flex-col items-center justify-center min-h-screen p-6"
    >
       <button 
        onClick={() => setView('MODE_SELECT')}
        className="absolute top-6 left-6 flex items-center gap-2 text-gray-400 hover:text-king-dark transition-colors"
      >
        <ChevronLeftIcon /> Back
      </button>

      <h2 className="text-2xl font-serif font-bold mb-8">How many players?</h2>

      <div className="flex gap-4">
        {[2, 3, 4].map((num) => (
          <motion.button
            key={num}
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            onClick={() => { setLudoPlayerCount(num as 2|3|4); startOfflineGame(); }}
            className="w-20 h-20 rounded-2xl bg-white shadow-lg border-2 border-transparent hover:border-king-gold flex items-center justify-center text-3xl font-bold font-serif text-king-dark"
          >
            {num}
          </motion.button>
        ))}
      </div>
    </motion.div>
  );

  const renderLobby = () => (
    <motion.div 
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="flex flex-col items-center justify-center min-h-screen p-6"
    >
      <button 
        onClick={() => { setView('MODE_SELECT'); setLobbyMode(null); peerManager.destroy(); }}
        className="absolute top-6 left-6 flex items-center gap-2 text-gray-400 hover:text-king-dark transition-colors"
      >
        <ChevronLeftIcon /> Back
      </button>

      <div className="max-w-md w-full bg-white p-8 rounded-3xl shadow-xl border border-gray-100 text-center">
        <h2 className="text-2xl font-serif font-bold mb-2">
           {gameType === GameType.CHESS ? 'Chess Lobby' : 'Ludo Lobby'}
        </h2>
        <p className="text-gray-500 mb-8">Connect with your opponent</p>

        {!lobbyMode ? (
          <div className="space-y-4">
             <button
               onClick={handleCreateGame}
               className="w-full py-4 bg-king-gold text-white rounded-xl font-bold text-lg hover:brightness-110 transition-all flex items-center justify-center gap-2"
             >
               <Crown size={20} /> Create Room
             </button>
             <div className="relative py-2">
                <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-200"></div></div>
                <div className="relative flex justify-center"><span className="bg-white px-2 text-sm text-gray-400">OR</span></div>
             </div>
             <div className="flex gap-2">
               <input 
                 value={joinCode}
                 onChange={(e) => setJoinCode(e.target.value.toUpperCase())}
                 placeholder="Enter Room Code"
                 className="flex-1 px-4 py-3 border border-gray-200 rounded-xl focus:border-king-gold outline-none uppercase tracking-widest text-center"
               />
               <button
                 onClick={handleJoinGame}
                 disabled={joinCode.length < 3}
                 className="px-6 py-3 bg-king-dark text-white rounded-xl font-bold disabled:opacity-50 hover:bg-black transition-colors"
               >
                 Join
               </button>
             </div>
          </div>
        ) : lobbyMode === 'CREATE' ? (
          <div className="flex flex-col items-center">
            <div className="w-20 h-20 rounded-full bg-king-gold/10 flex items-center justify-center mb-6 relative">
               <div className="absolute inset-0 rounded-full border-4 border-king-gold border-t-transparent animate-spin"></div>
               <Users className="text-king-gold" size={32} />
            </div>
            <p className="mb-2 text-gray-500">Share this code with your friend:</p>
            <div 
              onClick={copyToClipboard}
              className="group cursor-pointer bg-gray-50 border-2 border-dashed border-gray-300 rounded-xl px-8 py-4 mb-6 relative hover:border-king-gold transition-colors"
            >
               <span className="text-3xl font-mono font-bold tracking-wider text-king-dark">
                 {roomCode || "..."}
               </span>
               <div className="absolute -top-3 -right-3 bg-white shadow-sm border border-gray-100 rounded-full p-2 text-gray-400 group-hover:text-king-gold transition-colors">
                  {isCopied ? <Check size={16} /> : <Copy size={16} />}
               </div>
            </div>
            <p className="text-sm text-gray-400 animate-pulse">Waiting for opponent to join...</p>
          </div>
        ) : (
          <div className="flex flex-col items-center py-8">
             <div className="w-16 h-16 border-4 border-king-dark border-t-transparent rounded-full animate-spin mb-4"></div>
             <p>Connecting to room...</p>
          </div>
        )}
      </div>
    </motion.div>
  );

  const renderGame = () => (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="w-full h-full"
    >
      {gameType === GameType.CHESS && (
        <ChessGame 
          isHost={isHost}
          playMode={playMode}
          onExit={triggerExit}
          onGameOver={handleGameOver}
        />
      )}
      {gameType === GameType.LUDO && (
        <LudoGame
          isHost={isHost}
          playMode={playMode}
          playerCount={ludoPlayerCount}
          onExit={triggerExit}
          onGameOver={handleGameOver}
        />
      )}
    </motion.div>
  );

  return (
    <div className="min-h-screen bg-texture bg-fixed font-sans text-king-dark selection:bg-king-gold selection:text-white relative">
      <AnimatePresence mode="wait">
        {view === 'WELCOME' && renderWelcome()}
        {view === 'SELECTION' && renderSelection()}
        {view === 'MODE_SELECT' && renderModeSelect()}
        {view === 'PLAYERS_SELECT' && renderPlayerSelect()}
        {view === 'LOBBY' && renderLobby()}
        {view === 'GAME' && renderGame()}
      </AnimatePresence>

      {/* Exit Modal */}
      <AnimatePresence>
        {showExitModal && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
          >
             <motion.div
               initial={{ scale: 0.9, y: 20 }}
               animate={{ scale: 1, y: 0 }}
               exit={{ scale: 0.9, y: 20 }}
               className="bg-white p-8 rounded-3xl shadow-2xl max-w-sm w-full border border-gray-200"
             >
                <div className="flex justify-center mb-4 text-red-500">
                    <AlertTriangle size={48} />
                </div>
                <h3 className="text-2xl font-serif font-bold text-center mb-2">Leave Match?</h3>
                <p className="text-center text-gray-500 mb-8">
                   Are you sure you want to quit? Current progress will be lost.
                </p>
                <div className="flex gap-4">
                  <button 
                    onClick={() => setShowExitModal(false)}
                    className="flex-1 py-3 bg-gray-100 text-gray-700 rounded-xl font-bold hover:bg-gray-200 transition-colors"
                  >
                    Cancel
                  </button>
                  <button 
                    onClick={confirmExit}
                    className="flex-1 py-3 bg-red-500 text-white rounded-xl font-bold hover:bg-red-600 transition-colors"
                  >
                    Quit Game
                  </button>
                </div>
             </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Premium Winner Modal */}
      <AnimatePresence>
        {gameResults && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md"
          >
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ type: "spring", bounce: 0.4 }}
              className="bg-gradient-to-b from-gray-900 to-black p-1 rounded-3xl shadow-2xl max-w-sm w-full relative overflow-hidden"
            >
              {/* Gold Border Effect */}
              <div className="absolute inset-0 bg-gradient-to-tr from-king-gold via-yellow-200 to-king-gold opacity-20 animate-pulse"></div>

              <div className="bg-[#1A1A1D] rounded-[22px] p-8 relative z-10 text-center border border-king-gold/30">
                <div className="absolute top-0 left-0 right-0 h-32 bg-gradient-to-b from-king-gold/10 to-transparent -z-10"></div>

                <motion.div 
                  initial={{ y: -20 }} 
                  animate={{ y: 0 }} 
                  transition={{ delay: 0.2 }}
                  className="mb-6 relative inline-block"
                >
                  <Crown size={80} className="text-king-gold drop-shadow-[0_0_15px_rgba(212,175,55,0.5)]" />
                  <motion.div 
                    animate={{ rotate: 360 }} 
                    transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
                    className="absolute -inset-8 border-2 border-dashed border-king-gold/30 rounded-full"
                  />
                </motion.div>

                <h2 className="text-4xl font-serif font-bold text-white mb-2 tracking-wide drop-shadow-md">
                   Victory!
                </h2>

                <div className="text-king-gold font-bold text-xl mb-8 uppercase tracking-widest">
                  {gameResults[0]}
                </div>

                {/* Leaderboard */}
                <div className="bg-white/5 rounded-xl p-4 mb-8 space-y-3">
                   <h3 className="text-xs text-gray-400 uppercase tracking-widest font-bold mb-3 border-b border-white/10 pb-2">Match Results</h3>
                   {gameResults.map((player, index) => (
                     <div key={index} className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                           <div className={`
                             w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold
                             ${index === 0 ? 'bg-king-gold text-black' : 'bg-gray-700 text-gray-400'}
                           `}>
                             {index + 1}
                           </div>
                           <span className={`font-serif ${index === 0 ? 'text-white font-bold' : 'text-gray-400'}`}>
                             {player}
                           </span>
                        </div>
                        {index === 0 && <Star size={14} className="text-king-gold fill-king-gold" />}
                     </div>
                   ))}
                </div>

                <div className="space-y-3">
                   <button 
                     onClick={() => setGameResults(null)}
                     className="w-full py-4 bg-king-gold text-black rounded-xl font-bold hover:bg-yellow-400 transition-all shadow-lg shadow-king-gold/20 flex items-center justify-center gap-2"
                   >
                     <Play size={18} fill="black" /> Play Again
                   </button>
                   <button 
                     onClick={resetGame}
                     className="w-full py-4 bg-white/5 text-gray-400 rounded-xl font-bold hover:bg-white/10 hover:text-white transition-all"
                   >
                     Return to Lobby
                   </button>
                </div>

                <div className="mt-8 pt-4 border-t border-white/5 text-[10px] text-gray-500 uppercase tracking-widest font-semibold">
                  Developer: Khalid Mahmud Joy
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

const ChevronLeftIcon = () => (
  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
)

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Chess, Square } from 'chess.js';
import { motion } from 'framer-motion';
import { peerManager } from '../services/PeerManager';
import { GameMessage, PlayMode } from '../types';
import { ChevronLeft, RefreshCw, Eye, EyeOff, Clock } from 'lucide-react';
import { CHESS_TIME_LIMIT } from '../constants';

interface ChessGameProps {
  isHost: boolean;
  playMode: PlayMode;
  onExit: () => void;
  onGameOver: (ranking: string[]) => void;
}

const ChessGame: React.FC<ChessGameProps> = ({ isHost, playMode, onExit, onGameOver }) => {
  const [game, setGame] = useState(new Chess());
  const [board, setBoard] = useState(game.board());
  const [selectedSquare, setSelectedSquare] = useState<Square | null>(null);
  const [possibleMoves, setPossibleMoves] = useState<string[]>([]);
  const [playerColor] = useState<'w' | 'b'>(isHost ? 'w' : 'b'); 
  const [orientation, setOrientation] = useState<'w' | 'b'>(isHost ? 'w' : 'b'); 

  const [capturedWhite, setCapturedWhite] = useState<string[]>([]);
  const [capturedBlack, setCapturedBlack] = useState<string[]>([]);

  // Settings
  const [showHints, setShowHints] = useState(true);

  // Timers (seconds)
  const [whiteTime, setWhiteTime] = useState(CHESS_TIME_LIMIT);
  const [blackTime, setBlackTime] = useState(CHESS_TIME_LIMIT);

  const isOnline = playMode === 'ONLINE';

  const finishGame = (winnerName: string, loserName: string) => {
      onGameOver([winnerName, loserName]);
  };

  useEffect(() => {
    // Timer Logic
    if (game.isGameOver()) return;

    const timer = setInterval(() => {
        if (game.turn() === 'w') {
            setWhiteTime(prev => {
                if (prev <= 0) { 
                    clearInterval(timer); 
                    finishGame("Black", "White (Timeout)");
                    return 0; 
                }
                return prev - 1;
            });
        } else {
            setBlackTime(prev => {
                if (prev <= 0) { 
                    clearInterval(timer); 
                    finishGame("White", "Black (Timeout)");
                    return 0; 
                }
                return prev - 1;
            });
        }
    }, 1000);

    return () => clearInterval(timer);
  }, [game]); // Removed onGameOver from deps to avoid loop if parent changes

  useEffect(() => {
    if (!isOnline) return;

    peerManager.onData = (msg: GameMessage) => {
      if (msg.type === 'MOVE') {
        const { from, to, promotion } = msg.payload;
        makeMove(from, to, promotion, false); 
      } else if (msg.type === 'RESTART') {
        resetBoard();
      }
    };
    return () => { peerManager.onData = null; }
  }, [game, isOnline]);

  const resetBoard = () => {
      const newGame = new Chess();
      setGame(newGame);
      setBoard(newGame.board());
      setCapturedWhite([]);
      setCapturedBlack([]);
      setPossibleMoves([]);
      setSelectedSquare(null);
      setWhiteTime(CHESS_TIME_LIMIT);
      setBlackTime(CHESS_TIME_LIMIT);
  }

  const playMoveSound = () => {
     try {
       const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
       if (AudioContext) {
         const ctx = new AudioContext();
         const osc = ctx.createOscillator();
         const gain = ctx.createGain();
         osc.connect(gain);
         gain.connect(ctx.destination);
         osc.frequency.setValueAtTime(200, ctx.currentTime);
         gain.gain.setValueAtTime(0.1, ctx.currentTime);
         gain.gain.exponentialRampToValueAtTime(0.00001, ctx.currentTime + 0.1);
         osc.start();
         osc.stop(ctx.currentTime + 0.1);
       }
     } catch (e) { }
  };

  const makeMove = (from: string, to: string, promotion: string = 'q', emit: boolean = true) => {
    try {
      const moveAttempt = { from, to, promotion };
      const result = game.move(moveAttempt);

      if (result) {
        setBoard(game.board());
        playMoveSound();
        setSelectedSquare(null);
        setPossibleMoves([]);

        if (result.captured) {
            if (result.color === 'w') {
                setCapturedBlack(prev => [...prev, result.captured!]);
            } else {
                setCapturedWhite(prev => [...prev, result.captured!]);
            }
        }

        if (isOnline && emit) {
          peerManager.send({
            type: 'MOVE',
            payload: { from, to, promotion }
          });
        }

        if (game.isGameOver()) {
            let winner = 'Draw';
            let loser = 'Draw';
            if (game.isCheckmate()) {
                if (game.turn() === 'w') {
                    winner = 'Black';
                    loser = 'White';
                } else {
                    winner = 'White';
                    loser = 'Black';
                }
            }
            if (isOnline) {
                // If I moved and caused game over, I check my color
                const amIWhite = playerColor === 'w';
                if (winner === 'White') winner = amIWhite ? 'You' : 'Opponent';
                if (winner === 'Black') winner = amIWhite ? 'Opponent' : 'You';

                if (loser === 'White') loser = amIWhite ? 'You' : 'Opponent';
                if (loser === 'Black') loser = amIWhite ? 'Opponent' : 'You';
            }
            setTimeout(() => finishGame(winner, loser), 500);
        }
      }
    } catch (e) {
      console.error("Invalid move", e);
    }
  };

  const handleSquareClick = (square: Square, piece: { type: string; color: string } | null) => {
    const currentTurn = game.turn();
    if (isOnline && currentTurn !== playerColor) return;

    if (piece && piece.color === currentTurn) {
      if (selectedSquare === square) {
        setSelectedSquare(null);
        setPossibleMoves([]);
      } else {
        setSelectedSquare(square);
        if (showHints) {
            const moves = game.moves({ square, verbose: true }).map((m: any) => m.to);
            setPossibleMoves(moves);
        }
      }
      return;
    }

    if (selectedSquare) {
      if (!showHints) {
          makeMove(selectedSquare, square);
      } else if (possibleMoves.includes(square)) {
          makeMove(selectedSquare, square);
      } else {
          setSelectedSquare(null);
          setPossibleMoves([]);
      }
    }
  };

  const formatTime = (seconds: number) => {
      const m = Math.floor(seconds / 60);
      const s = seconds % 60;
      return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const getPieceIcon = (type: string, color: string) => {
    const symbols: Record<string, string> = {
      p: '♟', n: '♞', b: '♝', r: '♜', q: '♛', k: '♚'
    };
    return symbols[type] || '';
  };

  const isDarkSquare = (i: number, j: number) => (i + j) % 2 === 1;

  const boardDisplay = orientation === 'w' ? board : [...board].reverse().map(row => [...row].reverse());

  const topPlayerName = isOnline ? "Opponent" : (orientation === 'w' ? "Black" : "White");
  const bottomPlayerName = isOnline ? "You" : (orientation === 'w' ? "White" : "Black");

  const isTopTurn = !isOnline && ((orientation === 'w' && game.turn() === 'b') || (orientation === 'b' && game.turn() === 'w'));
  const isBottomTurn = !isOnline && ((orientation === 'w' && game.turn() === 'w') || (orientation === 'b' && game.turn() === 'b'));

  const topTime = orientation === 'w' ? blackTime : whiteTime;
  const bottomTime = orientation === 'w' ? whiteTime : blackTime;

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 pb-20 md:pb-4 relative">

      {/* Controls */}
      <div className="absolute top-4 right-4 flex gap-2 z-10">
        <button 
            onClick={() => setShowHints(!showHints)}
            className="p-3 bg-white/10 backdrop-blur rounded-full shadow-lg text-king-gold hover:bg-white/20 transition-all"
        >
            {showHints ? <Eye size={24} /> : <EyeOff size={24} />}
        </button>
        {!isOnline && (
            <button 
                onClick={() => setOrientation(prev => prev === 'w' ? 'b' : 'w')}
                className="p-3 bg-white/10 backdrop-blur rounded-full shadow-lg text-king-gold hover:bg-white/20 transition-all"
            >
                <RefreshCw size={24} />
            </button>
        )}
      </div>

      {/* HUD - Top */}
      <div className={`w-full max-w-md flex justify-between items-center mb-4 glass-panel p-3 rounded-lg shadow-sm transition-all duration-300 ${isTopTurn ? 'border-king-gold ring-2 ring-king-gold/50' : ''}`}>
        <div className="flex items-center gap-2">
            <div className={`w-3 h-3 rounded-full ${isOnline ? (game.turn() !== playerColor ? 'bg-green-500 animate-pulse' : 'bg-gray-300') : (isTopTurn ? 'bg-green-500 animate-pulse' : 'bg-gray-300')}`}></div>
            <span className="font-serif font-bold text-gray-700">{topPlayerName}</span>
            <div className={`flex items-center gap-1 ml-2 px-2 py-0.5 rounded ${topTime < 60 ? 'bg-red-100 text-red-600' : 'bg-gray-100'}`}>
                <Clock size={12} /> <span className="font-mono font-bold text-sm">{formatTime(topTime)}</span>
            </div>
        </div>
        <div className="flex gap-1 text-xl">
             {(isOnline ? playerColor === 'w' : orientation === 'w') 
                ? capturedWhite.map((p, i) => <span key={i} className="text-black">{getPieceIcon(p, 'w')}</span>) 
                : capturedBlack.map((p, i) => <span key={i} className="text-white drop-shadow-md">{getPieceIcon(p, 'b')}</span>)
             }
        </div>
      </div>

      {/* Board */}
      <div className="relative p-1 bg-[#4a3b2b] rounded shadow-2xl">
        <div className="grid grid-cols-8 border-4 border-[#3d2f20]">
          {boardDisplay.map((row, i) => (
            row.map((square, j) => {
              const actualRowIndex = orientation === 'w' ? i : 7 - i;
              const actualColIndex = orientation === 'w' ? j : 7 - j;
              const squareName = String.fromCharCode(97 + actualColIndex) + (8 - actualRowIndex) as Square;

              const isSelected = selectedSquare === squareName;
              const isPossible = possibleMoves.includes(squareName);
              const isDark = isDarkSquare(actualRowIndex, actualColIndex);

              return (
                <div
                  key={`${i}-${j}`}
                  onClick={() => handleSquareClick(squareName, square)}
                  className={`
                    w-10 h-10 sm:w-14 sm:h-14 md:w-16 md:h-16 flex items-center justify-center text-3xl sm:text-4xl cursor-pointer relative
                    ${isDark ? 'bg-[#b58863]' : 'bg-[#f0d9b5]'}
                    ${isSelected ? 'ring-inset ring-4 ring-yellow-400' : ''}
                  `}
                >
                  {isPossible && showHints && !square && (
                    <div className="absolute w-3 h-3 bg-black/20 rounded-full" />
                  )}
                  {isPossible && showHints && square && (
                     <div className="absolute inset-0 ring-inset ring-4 ring-black/20" />
                  )}

                  {square && (
                    <motion.div
                      layoutId={`piece-${squareName}`} 
                      className={`${square.color === 'w' ? 'text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)]' : 'text-black drop-shadow-[0_1px_1px_rgba(255,255,255,0.5)]'}`}
                    >
                      {getPieceIcon(square.type, square.color)}
                    </motion.div>
                  )}

                  {j === 0 && <span className={`absolute left-0.5 top-0 text-[8px] sm:text-[10px] ${isDark ? 'text-[#f0d9b5]' : 'text-[#b58863]'}`}>{orientation === 'w' ? 8-i : i+1}</span>}
                  {i === 7 && <span className={`absolute right-0.5 bottom-0 text-[8px] sm:text-[10px] ${isDark ? 'text-[#f0d9b5]' : 'text-[#b58863]'}`}>{String.fromCharCode(97 + (orientation === 'w' ? j : 7-j))}</span>}
                </div>
              );
            })
          ))}
        </div>
      </div>

      {/* HUD - Bottom */}
      <div className={`w-full max-w-md flex justify-between items-center mt-4 glass-panel p-3 rounded-lg shadow-sm transition-all duration-300 ${isBottomTurn ? 'border-king-gold ring-2 ring-king-gold/50' : ''}`}>
        <div className="flex items-center gap-2">
            <div className={`w-3 h-3 rounded-full ${isOnline ? (game.turn() === playerColor ? 'bg-green-500 animate-pulse' : 'bg-gray-300') : (isBottomTurn ? 'bg-green-500 animate-pulse' : 'bg-gray-300')}`}></div>
            <span className="font-serif font-bold text-king-gold">{bottomPlayerName}</span>
             <div className={`flex items-center gap-1 ml-2 px-2 py-0.5 rounded ${bottomTime < 60 ? 'bg-red-100 text-red-600' : 'bg-gray-100'}`}>
                <Clock size={12} /> <span className="font-mono font-bold text-sm">{formatTime(bottomTime)}</span>
            </div>
        </div>
        <div className="flex gap-1 text-xl">
             {(isOnline ? playerColor === 'w' : orientation === 'w')
                 ? capturedBlack.map((p, i) => <span key={i} className="text-black">{getPieceIcon(p, 'b')}</span>) 
                 : capturedWhite.map((p, i) => <span key={i} className="text-white drop-shadow-md">{getPieceIcon(p, 'w')}</span>)
             }
        </div>
      </div>

      <button onClick={onExit} className="mt-8 flex items-center gap-2 text-gray-500 hover:text-red-500 transition-colors">
        <ChevronLeft size={20} /> Leave Game
      </button>

    </div>
  );
};

export default ChessGame;

import React, { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import { peerManager } from '../services/PeerManager';
import { GameMessage, LudoState, PlayMode, LudoColor } from '../types';
import { ChevronLeft, Dices, Timer } from 'lucide-react';
import { LUDO_PATHS, BASE_POSITIONS, SAFE_SPOTS, LUDO_TURN_TIME } from '../constants';

interface LudoGameProps {
  isHost: boolean;
  playMode: PlayMode;
  onExit: () => void;
  onGameOver: (ranking: string[]) => void;
  playerCount?: number; 
}

const COLORS: LudoColor[] = ['blue', 'red', 'yellow', 'green'];

const LudoGame: React.FC<LudoGameProps> = ({ isHost, playMode, onExit, onGameOver, playerCount = 2 }) => {
  const isOnline = playMode === 'ONLINE';
  const myColor: LudoColor = isHost ? 'blue' : 'green';

  const getActivePlayers = (count: number): LudoColor[] => {
      if (count === 2) return ['blue', 'green'];
      if (count === 3) return ['blue', 'red', 'yellow'];
      return ['blue', 'red', 'yellow', 'green'];
  };

  const [gameState, setGameState] = useState<LudoState>({
    blueTokens: [-1, -1, -1, -1],
    redTokens: [-1, -1, -1, -1],
    yellowTokens: [-1, -1, -1, -1],
    greenTokens: [-1, -1, -1, -1],
    currentTurn: 'blue',
    diceValue: null,
    canRoll: true,
    winner: null,
    activePlayers: isOnline ? ['blue', 'green'] : getActivePlayers(playerCount)
  });

  const [isRolling, setIsRolling] = useState(false);
  const [turnTime, setTurnTime] = useState(LUDO_TURN_TIME);

  useEffect(() => {
    if (gameState.winner) return;
    const timer = setInterval(() => {
        setTurnTime(prev => {
            if (prev <= 0) {
                passTurn();
                return LUDO_TURN_TIME;
            }
            return prev - 1;
        });
    }, 1000);
    return () => clearInterval(timer);
  }, [gameState.currentTurn, gameState.winner, gameState.canRoll]);

  useEffect(() => {
      setTurnTime(LUDO_TURN_TIME);
  }, [gameState.currentTurn]);

  useEffect(() => {
    if (!isOnline) return;
    peerManager.onData = (msg: GameMessage) => {
      if (msg.type === 'SYNC_STATE') {
        setGameState(msg.payload);
      } else if (msg.type === 'ROLL_DICE') {
         setIsRolling(true);
         setTimeout(() => setIsRolling(false), 500);
      }
    };
  }, [isOnline]);

  const broadcastState = (newState: LudoState) => {
    setGameState(newState);
    if (isOnline) {
        peerManager.send({ type: 'SYNC_STATE', payload: newState });
    }
    if (newState.winner) {
        handleWin(newState.winner as LudoColor, newState);
    }
  };

  // Calculate detailed rankings
  const handleWin = (winner: LudoColor, state: LudoState) => {
      const active = state.activePlayers;

      // Helper to calculate progress score
      // Score = (TokensHome * 1000) + Sum(TokenPositions)
      const getScore = (c: LudoColor) => {
          const tokens = getTokens(c, state);
          let score = 0;
          tokens.forEach(t => {
              if (t === 57) score += 1000;
              else if (t !== -1) score += t;
          });
          return score;
      };

      // Sort all active players by score, ensuring winner is first
      const rankedColors = active.sort((a, b) => {
          if (a === winner) return -1;
          if (b === winner) return 1;
          return getScore(b) - getScore(a);
      });

      // Map to display names
      const displayNames = rankedColors.map(c => {
          if (isOnline) {
              return c === myColor ? "You" : "Opponent";
          }
          const niceName: Record<string, string> = {
              'blue': 'Player 1 (Blue)',
              'green': 'Player 2 (Green)',
              'red': 'Player 3 (Red)',
              'yellow': 'Player 4 (Yellow)'
          };
          return niceName[c] || c.toUpperCase();
      });

      onGameOver(displayNames);
  };

  const getNextTurn = (current: LudoColor): LudoColor => {
      const all = ['blue', 'red', 'yellow', 'green'] as LudoColor[]; 
      let idx = all.indexOf(current);
      let next = all[(idx + 1) % 4];
      while (!gameState.activePlayers.includes(next)) {
          idx = all.indexOf(next);
          next = all[(idx + 1) % 4];
      }
      return next;
  };

  const passTurn = () => {
      const next = getNextTurn(gameState.currentTurn);
      broadcastState({
          ...gameState,
          currentTurn: next,
          diceValue: null,
          canRoll: true
      });
  };

  const rollDice = () => {
    if (isOnline && (gameState.currentTurn !== myColor || !gameState.canRoll)) return;
    if (!gameState.canRoll) return;

    setIsRolling(true);
    if (isOnline) peerManager.send({ type: 'ROLL_DICE', payload: {} });

    setTimeout(() => {
      setIsRolling(false);
      const roll = Math.floor(Math.random() * 6) + 1;

      const newState = { ...gameState, diceValue: roll, canRoll: false };

      const tokens = getTokens(newState.currentTurn, newState);
      const hasMoves = tokens.some(pos => canMove(pos, roll));

      if (!hasMoves) {
        setTimeout(() => {
            const next = getNextTurn(newState.currentTurn);
            broadcastState({ ...newState, currentTurn: next, canRoll: true, diceValue: null });
        }, 1000);
      } else {
        broadcastState(newState);
      }
    }, 500);
  };

  const getTokens = (color: LudoColor, state = gameState) => {
      switch(color) {
          case 'blue': return state.blueTokens;
          case 'red': return state.redTokens;
          case 'yellow': return state.yellowTokens;
          case 'green': return state.greenTokens;
      }
  };

  const getGlobalCoords = (color: LudoColor, pathIdx: number): string | null => {
      if (pathIdx === -1) return null; // Base
      const path = LUDO_PATHS[color];
      if (!path || !path[pathIdx]) return null;
      const [r, c] = path[pathIdx];
      return `${r}-${c}`;
  };

  const canMove = (pos: number, roll: number) => {
      if (pos === -1) return roll === 6; 
      if (pos >= 52) return pos + roll <= 57; 
      return true; 
  };

  const moveToken = (tokenIndex: number) => {
     if (isOnline && gameState.currentTurn !== myColor) return;
     if (gameState.canRoll || !gameState.diceValue) return;

     const color = gameState.currentTurn;
     const tokens = [...getTokens(color)];
     const currentPos = tokens[tokenIndex];

     if (!canMove(currentPos, gameState.diceValue)) return;

     let newPos = currentPos === -1 ? 0 : currentPos + gameState.diceValue!;

     // --- Capture Logic ---
     const newState = { ...gameState };
     const destCoords = getGlobalCoords(color, newPos);
     let captured = false;

     if (destCoords) {
         // Check if destination is safe
         const [r, c] = destCoords.split('-').map(Number);
         const isSafe = SAFE_SPOTS.some(s => s[0] === r && s[1] === c);

         if (!isSafe) {
             // Check against all other active players
             COLORS.forEach(oppColor => {
                 if (oppColor === color) return;
                 if (!gameState.activePlayers.includes(oppColor)) return;

                 const oppTokens = getTokens(oppColor, newState);
                 const oppTokensCopy = [...oppTokens];
                 let modified = false;

                 oppTokens.forEach((p, idx) => {
                     const oppCoords = getGlobalCoords(oppColor, p);
                     if (oppCoords === destCoords) {
                         // CAPTURE!
                         oppTokensCopy[idx] = -1; // Send to base
                         modified = true;
                         captured = true;
                     }
                 });

                 if (modified) {
                     // Update state for opponent
                     if (oppColor === 'blue') newState.blueTokens = oppTokensCopy;
                     if (oppColor === 'red') newState.redTokens = oppTokensCopy;
                     if (oppColor === 'yellow') newState.yellowTokens = oppTokensCopy;
                     if (oppColor === 'green') newState.greenTokens = oppTokensCopy;
                 }
             });
         }
     }

     // Update current token
     tokens[tokenIndex] = newPos;
     if (color === 'blue') newState.blueTokens = tokens;
     if (color === 'red') newState.redTokens = tokens;
     if (color === 'yellow') newState.yellowTokens = tokens;
     if (color === 'green') newState.greenTokens = tokens;

     // Win Check
     const allHome = tokens.every(t => t === 57);
     const winner = allHome ? color : null;
     newState.winner = winner;

     // Next Turn Logic (6 = Extra Turn, but not if winner)
     const roll = gameState.diceValue;
     // Note: Standard rules often give extra turn on capture too, but we'll stick to just 6 or capture if requested later.
     // Prompt just said "after 6 it may come again".
     const nextTurn = (roll === 6 && !winner) ? color : getNextTurn(color);

     newState.diceValue = null;
     newState.canRoll = true;
     newState.currentTurn = nextTurn;

     broadcastState(newState);
  };

  const getTokensAt = (row: number, col: number) => {
      const result: {color: LudoColor, index: number}[] = [];
      COLORS.forEach(c => {
          if (!gameState.activePlayers.includes(c)) return;
          const tokens = getTokens(c);
          tokens.forEach((pos, idx) => {
              let tRow = 0, tCol = 0;
              if (pos === -1) {
                  const base = BASE_POSITIONS[c][idx];
                  tRow = base[0]; tCol = base[1];
              } else {
                  const path = LUDO_PATHS[c];
                  if (path && path[pos]) {
                     tRow = path[pos][0];
                     tCol = path[pos][1];
                  }
              }
              if (tRow === row && tCol === col) {
                  result.push({color: c, index: idx});
              }
          });
      });
      return result;
  };

  const gridElements = [];
  for (let r = 0; r < 15; r++) {
      for (let c = 0; c < 15; c++) {
          const tokensHere = getTokensAt(r, c);

          // Render Cell Logic
          let cellColor = 'bg-white';
          if (r < 6 && c < 6) cellColor = 'bg-blue-500 border-blue-600 border'; // Blue Base
          else if (r < 6 && c > 8) cellColor = 'bg-red-500 border-red-600 border'; // Red Base
          else if (r > 8 && c < 6) cellColor = 'bg-yellow-500 border-yellow-600 border'; // Yellow Base
          else if (r > 8 && c > 8) cellColor = 'bg-green-500 border-green-600 border'; // Green Base
          else if (r >= 6 && r <= 8 && c >= 6 && c <= 8) cellColor = 'bg-gray-100'; // Center
          else {
            // Paths
            if (r === 7 && c > 0 && c < 6) cellColor = 'bg-blue-500';
            else if (r === 6 && c === 1) cellColor = 'bg-blue-500'; 
            else if (c === 7 && r > 0 && r < 6) cellColor = 'bg-red-500';
            else if (c === 8 && r === 1) cellColor = 'bg-red-500';
            else if (c === 7 && r > 8 && r < 14) cellColor = 'bg-yellow-500';
            else if (c === 6 && r === 13) cellColor = 'bg-yellow-500';
            else if (r === 7 && c > 8 && c < 14) cellColor = 'bg-green-500';
            else if (r === 8 && c === 13) cellColor = 'bg-green-500';
          }

          gridElements.push(
              <div key={`${r}-${c}`} className={`relative w-full h-full border border-gray-300 ${cellColor}`}>
                  <div className="absolute inset-0 flex items-center justify-center flex-wrap p-0.5 pointer-events-none">
                      {tokensHere.map((t, i) => {
                          const isCurrentTurn = gameState.currentTurn === t.color;
                          const tokenVal = getTokens(t.color)[t.index];
                          const movable = isCurrentTurn && !gameState.canRoll && gameState.diceValue && canMove(tokenVal, gameState.diceValue);

                          return (
                              <motion.div
                                key={`${t.color}-${t.index}`}
                                onClick={(e) => { e.stopPropagation(); if (movable) moveToken(t.index); }}
                                className={`
                                    w-3 h-3 md:w-4 md:h-4 rounded-full shadow-md border border-white pointer-events-auto
                                    ${t.color === 'blue' ? 'bg-blue-700' : ''}
                                    ${t.color === 'red' ? 'bg-red-800' : ''}
                                    ${t.color === 'yellow' ? 'bg-yellow-400' : ''}
                                    ${t.color === 'green' ? 'bg-green-700' : ''}
                                    ${movable ? 'cursor-pointer animate-pulse ring-2 ring-white z-10 scale-125' : ''}
                                `}
                                layoutId={`${t.color}-${t.index}`}
                              />
                          );
                      })}
                  </div>
              </div>
          );
      }
  }

  // --- Dice Component ---
  const DiceControl = ({ color }: { color: LudoColor }) => {
      const isMyTurn = gameState.currentTurn === color;
      const isActive = gameState.activePlayers.includes(color);

      if (!isActive) return <div className="w-16 h-16 opacity-0" />; // Spacer

      return (
          <div className={`flex flex-col items-center justify-center p-2 rounded-xl transition-all ${isMyTurn ? 'bg-white shadow-lg scale-110 z-10' : 'opacity-60 scale-90'}`}>
              <button
                 onClick={() => isMyTurn && rollDice()}
                 disabled={!isMyTurn || !gameState.canRoll}
                 className={`
                    w-12 h-12 rounded-lg flex items-center justify-center text-white shadow-md transition-all
                    ${color === 'blue' ? 'bg-blue-500' : ''}
                    ${color === 'red' ? 'bg-red-500' : ''}
                    ${color === 'yellow' ? 'bg-yellow-500' : ''}
                    ${color === 'green' ? 'bg-green-500' : ''}
                    ${isMyTurn && gameState.canRoll ? 'animate-bounce ring-2 ring-offset-2 ring-king-gold' : ''}
                 `}
              >
                  {isMyTurn && isRolling ? (
                      <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 0.5 }}>
                          <Dices size={24} />
                      </motion.div>
                  ) : (
                      (isMyTurn && gameState.diceValue) ? <span className="text-xl font-bold">{gameState.diceValue}</span> : <Dices size={24} />
                  )}
              </button>
          </div>
      );
  }

  return (
    <div className="flex flex-col items-center min-h-screen p-2 bg-gray-50 relative overflow-hidden">

        {/* Header */}
        <div className="w-full flex justify-between items-center max-w-lg mb-2 px-4 pt-4 z-20">
             <button onClick={onExit} className="p-2 rounded-full bg-white shadow text-gray-600"><ChevronLeft /></button>
             <h2 className="text-xl font-bold font-serif text-king-dark">Ludo Royal</h2>
             <div className={`flex items-center gap-1 font-mono font-bold bg-white px-2 py-1 rounded shadow ${turnTime < 10 ? 'text-red-500' : 'text-gray-600'}`}>
                 <Timer size={14} /> {turnTime}s
             </div>
        </div>

        {/* Board Container */}
        <div className="relative w-full max-w-md aspect-square bg-white shadow-2xl rounded-lg border-4 border-gray-800 p-1">
             <div className="grid grid-cols-15 grid-rows-15 w-full h-full">
                 {gridElements}
             </div>

             {/* Dice Overlays - Positioned near bases */}
             <div className="absolute top-4 left-4 pointer-events-none"><div className="pointer-events-auto"><DiceControl color="blue" /></div></div>
             <div className="absolute top-4 right-4 pointer-events-none"><div className="pointer-events-auto"><DiceControl color="red" /></div></div>
             <div className="absolute bottom-4 left-4 pointer-events-none"><div className="pointer-events-auto"><DiceControl color="yellow" /></div></div>
             <div className="absolute bottom-4 right-4 pointer-events-none"><div className="pointer-events-auto"><DiceControl color="green" /></div></div>
        </div>

        <div className="mt-4 text-center text-gray-500 text-sm">
             {gameState.diceValue && !gameState.canRoll 
                ? `${gameState.currentTurn.toUpperCase()} must move` 
                : `${gameState.currentTurn.toUpperCase()}'s Roll`}
        </div>

        <style>{`
          .grid-cols-15 { grid-template-columns: repeat(15, 1fr); }
          .grid-rows-15 { grid-template-rows: repeat(15, 1fr); }
        `}</style>
    </div>
  );
};

