import Peer, { DataConnection } from 'peerjs';
import { GameMessage } from '../types';

export class PeerManager {
  private peer: Peer | null = null;
  private conn: DataConnection | null = null;
  private myId: string = '';

  // Callbacks
  public onData: ((data: GameMessage) => void) | null = null;
  public onConnect: (() => void) | null = null;
  public onClose: (() => void) | null = null;

  constructor() {}

  public init(username: string): Promise<string> {
    return new Promise((resolve, reject) => {
      // Generate a short ID for usability (6 chars)
      const shortId = Math.random().toString(36).substring(2, 8).toUpperCase();

      // CRITICAL: Add STUN servers for mobile/cellular network traversal
      const config = {
        debug: 1,
        config: {
          iceServers: [
            { urls: 'stun:stun.l.google.com:19302' },
            { urls: 'stun:global.stun.twilio.com:3478' }
          ]
        }
      };

      this.peer = new Peer(shortId, config);

      this.peer.on('open', (id) => {
        this.myId = id;
        console.log('My Peer ID is: ' + id);
        resolve(id);
      });

      this.peer.on('connection', (conn) => {
        this.handleConnection(conn);
      });

      this.peer.on('error', (err) => {
        console.error('PeerJS Error:', err);
        // Don't reject immediately on minor errors, but log them
      });

      this.peer.on('disconnected', () => {
          console.log('Peer disconnected from server.');
          // Optional: this.peer.reconnect();
      });
    });
  }

  public connectTo(peerId: string): void {
    if (!this.peer) return;

    // Explicitly clean up old connection if exists
    if (this.conn) {
        this.conn.close();
    }

    const conn = this.peer.connect(peerId.toUpperCase(), {
        reliable: true
    });
    this.handleConnection(conn);
  }

  private handleConnection(conn: DataConnection) {
    this.conn = conn;

    this.conn.on('open', () => {
      console.log('Connection established');
      if (this.onConnect) this.onConnect();
    });

    this.conn.on('data', (data) => {
      if (this.onData) this.onData(data as GameMessage);
    });

    this.conn.on('close', () => {
      console.log('Connection closed');
      this.conn = null;
      if (this.onClose) this.onClose();
    });

    this.conn.on('error', (err) => {
      console.error('Connection error:', err);
    });
  }

  public send(msg: GameMessage) {
    if (this.conn && this.conn.open) {
      this.conn.send(msg);
    } else {
      console.warn('Connection not open, cannot send message');
    }
  }

  public getMyId() {
    return this.myId;
  }

  public destroy() {
    if (this.peer) {
      this.peer.destroy();
      this.peer = null;
    }
    this.conn = null;
  }
}

export const peerManager = new PeerManager();

